function solve(n, edges, k) {
    edges.sort((a, b) => a[2] - b[2]);
    let max_time = edges.length > 0 ? edges[edges.length - 1][2] : 0;
    let low = 0, high = max_time;
    let answer = max_time;

    while (low <= high) {
        let mid = Math.floor((low + high) / 2);
        let count = check(n, edges, mid, k);
        if (count >= k) {
            answer = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    return answer;
}

function check(n, edges, t, k) {
    let adj = new Array(n).fill().map(() => []);
    for (let [u, v, time] of edges) {
        if (time > t) {
            adj[u].push(v);
            adj[v].push(u);
        }
    }

    let visited = new Array(n).fill(false);
    let components = 0;

    for (let i = 0; i < n; i++) {
        if (!visited[i]) {
            components++;
            let queue = [i];
            visited[i] = true;
            while (queue.length > 0) {
                let node = queue.shift();
                for (let neighbor of adj[node]) {
                    if (!visited[neighbor]) {
                        visited[neighbor] = true;
                        queue.push(neighbor);
                    }
                }
            }
        }
    }

    return components;
}

