#include <vector>
#include <queue>
#include <algorithm>

using namespace std;

long long solve(long long n, vector<vector<long long>> edges, long long k) {
    sort(edges.begin(), edges.end(), [](const vector<long long>& a, const vector<long long>& b) {
        return a[2] < b[2];
    });

    long long max_time = 0;
    if (!edges.empty()) {
        max_time = edges.back()[2];
    }

    long long low = 0, high = max_time;
    long long answer = max_time;

    while (low <= high) {
        long long mid = (low + high) / 2;
        long long components = check(n, edges, mid, k);
        if (components >= k) {
            answer = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    return answer;
}

long long check(long long n, vector<vector<long long>>& edges, long long t, long long k) {
    vector<vector<long long>> adj(n);
    for (const auto& edge : edges) {
        if (edge[2] > t) {
            adj[edge[0]].push_back(edge[1]);
            adj[edge[1]].push_back(edge[0]);
        }
    }

    vector<bool> visited(n, false);
    long long components = 0;

    for (long long i = 0; i < n; ++i) {
        if (!visited[i]) {
            components++;
            queue<long long> q;
            q.push(i);
            visited[i] = true;
            while (!q.empty()) {
                long long node = q.front();
                q.pop();
                for (long long neighbor : adj[node]) {
                    if (!visited[neighbor]) {
                        visited[neighbor] = true;
                        q.push(neighbor);
                    }
                }
            }
        }
    }

    return components;
}
